#include<stdio.h>
int a[10002],n;
void down(int k){while(2*k<=n){int j=2*k;if(j+1<=n&&a[j+1]>a[j])j++;if(a[k]>=a[j])break;int t=a[k];a[k]=a[j];a[j]=t;k=j;}}
int main(){scanf("%d",&n);for(int i=1;i<=n;i++)scanf("%d",&a[i]);down(1);for(int i=1;i<=n;i++)printf("%d%c",a[i],i<n?' ':'\n');}
